# FreeSense foreign-config package map (shared by the GUI importer and the
# installer importer so the two flows never drift).
#
# Format (one mapping per line, whitespace-separated):
#   <lineage>  <source-package>  <freesense-package-or-hyphen>  <confidence>
#
#   lineage:     pfsense | opnsense
#   source:      the source distribution's package/plugin name
#                (OPNsense: with or without the os- prefix; a bare os- name is
#                 matched by stripping the prefix at lookup time)
#   freesense:   the FreeSense package internal name (as used in
#                <installedpackages>), or "-" when there is no equivalent
#   confidence:  exact | likely | guess | core | none
#                exact/likely -> pre-check for the user
#                guess        -> suggest, leave un-checked
#                core         -> built into FreeSense, no package needed
#                none         -> no equivalent, reported as skipped
#
# pfSense is rebranded pfSense CE, so any pfSense package not listed here still
# maps 1:1 by name at runtime (identity fallback). This file only needs the
# OPNsense translations and any pfSense special-cases; the pfSense identity list
# is kept for completeness and to flag packages FreeSense does not ship.
#
# Keep the FreeSense column in sync with the repo catalog:
#   pkg rquery -r FreeSense '%n' | sed -n 's/^FreeSense-pkg-//p'

# ---- pfSense CE -> FreeSense (identity; same lineage) ----
pfsense  acme                    acme                    exact
pfsense  apcupsd                 apcupsd                 exact
pfsense  arping                  arping                  exact
pfsense  arpwatch                arpwatch                exact
pfsense  Avahi                   Avahi                   exact
